  const tabSessionIds = useWorkspaceLayoutStore((s) => s.layouts[workspace.id]?.chatTabSessionIds);
  const hasUnseenActivity = useUnreadStore((s) => {
    const ids = tabSessionIds?.length
      ? tabSessionIds
