  1→import React, { useState } from "react";
  2→import { match } from "ts-pattern";
  3→import { Archive, Loader2 } from "lucide-react";
  4→import NumberFlow from "@number-flow/react";
  5→
  6→import { cn } from "@/shared/lib/utils";
  7→import { useWorkingDuration, formatDuration, useIsMobile, useLongPress } from "@/shared/hooks";
  8→import { CircularPixelGrid } from "@/features/session/ui/CircularPixelGrid";
  9→import { useUnreadStore } from "@/features/session/store/unreadStore";
 10→import { useWorkspaceLayoutStore } from "@/features/workspace/store/workspaceLayoutStore";
 11→import { getDisplayStatus, STATUS_CONFIG } from "../lib/status";
 12→import { getWorkspaceDisplayName, getWorkspaceSecondaryText } from "../lib/utils";
 13→import type { WorkspaceItemProps } from "../model/types";
 14→import { SidebarRow, SidebarRowIconSlot } from "./SidebarRow";
 15→import { WorkflowStatusIcon } from "./WorkflowStatusIcon";
 16→import { WorkspaceStatusMenu } from "./WorkspaceStatusMenu";
 17→import { WorkspaceActionSheet } from "./WorkspaceActionSheet";
 18→
 19→/**
 20→ * WorkspaceItem — Sidebar workspace row
 21→ *
 22→ * Layout:  [Left (flex-1)]  [Right]
 23→ *   Left:
 24→ *     Row 1: [Icon 20×20] [display name]   (title > slug > branch)
 25→ *     Row 2: [pad-left 26px] [secondary · status]
 26→ *   Right:
 27→ *     [+additions -deletions]
 28→ *
 29→ * Display name priority: workspace.title (PR/user) → slug → git_branch → "New workspace"
 30→ * Secondary line: shows slug when title is primary, otherwise just status info.
 31→ *
 32→ * Icons: working → CircularPixelGrid working, error → red dot, unread → gold dot.
 33→ * Idle → no icon (26px indent).
 34→ *
 35→ * State: "initializing" → shimmer row with CircularPixelGrid working + "Setting up..."
 36→ */
 37→export const WorkspaceItem = React.memo(function WorkspaceItem({
 38→  workspace,
 39→  isActive,
 40→  diffStats,
 41→  onClick,
 42→  onArchive,
 43→  onStatusChange,
 44→}: WorkspaceItemProps) {
 45→  const isInitializing = workspace.state === "initializing";
 46→
 47→  // Hooks must be called unconditionally (React rules of hooks)
 48→  const { duration } = useWorkingDuration({
 49→    status: workspace.session_status,
 50→    latestMessageSentAt: workspace.latest_message_sent_at,
 51→  });
 52→
 53→  // Check all sessions in this workspace's tabs for unseen activity,
 54→  // not just current_session_id — the user may have multiple tabs open.
 55→  const tabSessionIds = useWorkspaceLayoutStore((s) => s.layouts[workspace.id]?.chatTabSessionIds);
 56→  const hasUnseenActivity = useUnreadStore((s) => {
 57→    const ids = tabSessionIds?.length
 58→      ? tabSessionIds
 59→      : workspace.current_session_id
 60→        ? [workspace.current_session_id]
 61→        : [];
 62→    return ids.some((sid) => s.unreadSessionIds[sid]);
 63→  });
 64→
 65→  // Mobile: long-press opens action sheet instead of hover archive button
 66→  const isMobile = useIsMobile();
 67→  const [actionSheetOpen, setActionSheetOpen] = useState(false);
 68→  const longPress = useLongPress(() => setActionSheetOpen(true));
 69→
 70→  // Initializing state: non-interactive row with loading animation
 71→  if (isInitializing) {
 72→    const initSecondary = getWorkspaceSecondaryText(workspace);
 73→    return (
 74→      <div className="animate-[fadeInUp_0.25s_cubic-bezier(.215,.61,.355,1)]">
 75→        <SidebarRow
 76→          variant="workspace"
 77→          isActive={false}
 78→          aria-label="Workspace setting up"
 79→          className="pointer-events-none"
 80→        >
 81→          <div className="flex min-w-0 flex-1 animate-[shimmer_2s_ease-in-out_infinite] flex-col gap-0.5">
 82→            {/* Row 1: thinking icon + display name */}
 83→            <div className="flex min-w-0 items-center gap-1.5">
 84→              <SidebarRowIconSlot>
 85→                <CircularPixelGrid variant="working" size={14} resolution={8} />
 86→              </SidebarRowIconSlot>
 87→              <span className="text-text-disabled truncate text-base font-normal">
 88→                {getWorkspaceDisplayName(workspace)}
 89→              </span>
 90→            </div>
 91→            {/* Row 2: secondary context · init stage */}
 92→            <div className="flex min-w-0 items-center gap-1.5 pl-[26px]">
 93→              {initSecondary && (
 94→                <>
 95→                  <span className="text-text-disabled truncate text-xs">{initSecondary}</span>
 96→                  <span className="text-text-disabled text-xs">·</span>
 97→                </>
 98→              )}
 99→              <span className="text-text-muted shrink-0 text-xs">
100→                {match(workspace.init_stage)
101→                  .with("worktree", () => "Creating worktree...")
102→                  .with("dependencies", () => "Installing dependencies...")
103→                  .with("hooks", () => "Setting up environment...")
104→                  .with("session", () => "Finalizing...")
105→                  .otherwise(() => "Setting up...")}
106→              </span>
107→            </div>
108→          </div>
109→        </SidebarRow>
110→      </div>
111→    );
112→  }
113→
114→  const formatTime = (timestamp: string) => {
115→    const date = new Date(timestamp);
116→    const now = new Date();
117→    const diffMs = now.getTime() - date.getTime();
118→    const diffMins = Math.floor(diffMs / 60000);
119→    const diffHours = Math.floor(diffMins / 60);
120→    const diffDays = Math.floor(diffHours / 24);
121→    const diffMonths = Math.floor(diffDays / 30);
122→
123→    if (diffMins < 1) return "now";
124→    if (diffMins < 60) return `${diffMins}m ago`;
125→    if (diffHours < 24) return `${diffHours}h ago`;
126→    if (diffDays < 30) return `${diffDays}d ago`;
127→    return `${diffMonths}mo ago`;
128→  };
129→
